  (119, 3, 'Three of these figures are rotations of one figure. Select the one that is most unlike the others.', '["<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 110 110\" width=\"104\" height=\"104\" role=\"img\"><rect x=\"0\" y=\"0\" width=\"110\" height=\"110\" fill=\"#ffffff\"/><rect x=\"3\" y=\"3\" width=\"104\" height=\"104\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/><g transform=\"translate(55,55) rotate(135) scale(0.85)\"><g transform=\"translate(0,16) rotate(0) scale(1.6)\"><path d=\"M -3 3 L -3 -15 A 18 18 0 0 1 15 3 Z\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2.5\"/></g><g transform=\"translate(28,-20) rotate(0) scale(0.55)\"><polyline points=\"13,-14 -8,-14 -8,0 8,0 8,14 -13,14\" fill=\"none\" stroke=\"#111111\" stroke-width=\"4.5\"/></g><rect x=\"-38\" y=\"-30\" width=\"16\" height=\"16\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/></g></svg>", "<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 110 110\" width=\"104\" height=\"104\" role=\"img\"><rect x=\"0\" y=\"0\" width=\"110\" height=\"110\" fill=\"#ffffff\"/><rect x=\"3\" y=\"3\" width=\"104\" height=\"104\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/><g transform=\"translate(55,55) rotate(180) scale(0.85)\"><g transform=\"translate(0,16) rotate(0) scale(1.6)\"><path d=\"M -3 3 L -3 -15 A 18 18 0 0 1 15 3 Z\" fill=\"#bbbbbb\" stroke=\"#111111\" stroke-width=\"2.5\"/></g><g transform=\"translate(28,-20) rotate(0) scale(0.55)\"><polyline points=\"13,-14 -8,-14 -8,0 8,0 8,14 -13,14\" fill=\"none\" stroke=\"#111111\" stroke-width=\"4.5\"/></g><rect x=\"-38\" y=\"-30\" width=\"16\" height=\"16\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/></g></svg>", "<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 110 110\" width=\"104\" height=\"104\" role=\"img\"><rect x=\"0\" y=\"0\" width=\"110\" height=\"110\" fill=\"#ffffff\"/><rect x=\"3\" y=\"3\" width=\"104\" height=\"104\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2